// 在此输入自定义内容
function fun () {
  const args = []
  const buildParams = () => {
      if (options.pathParams.length) {
          if (options.pathParams.length > 1) {
              args.push(`pathParams: Expand<${options.pathParamsType}>`);
          } else {
              // 如果只有一个路径参数，直接传递其值
              args.push(
                  `${options.pathParams[0].name}: ${options.buildParameters(options.pathParams[0])}`
              );
          }
      }
      if (options.queryParams.length) {
          args.push(`params: Expand<${options.queryParamsType}>`);
      }
      if (!["get", "delete", "head", "options"].includes(options.apiMethod || "get") && options.haveReqBody) {
          args.push(`data: Expand<${options.dataParamsType}>`);
      }
      args.push('config?: Expand<ParticalUniAppRequestOptions>')
  }
  buildParams()
  const url = `'${options.apiPath}'`;
  let bodyParams = ''
  if (["get", "delete", "head", "options"].includes(options.apiMethod)) {
    bodyParams = options.queryParams.length ? `params, ` : '{}, '
  } else {
    bodyParams = options.haveReqBody ? 'data, ' : '{}, '
  }

  return `export const ${options.apiFunctionName} = async (${args.join(", ")}): Promise<Expand<${options.apiFunctionName}Res>> => {${'\n'}    const _config= baseURL ? { baseURL, ...config } : config ${'\n'}    return http.${options.apiMethod}(${url}, ${bodyParams}_config);${'\n'}}`
}
fun()
